def _env(name: str, default: str = None) -> str:
    v = os.getenv(name, default)
    if v is None or v == "":
        raise ValueError(f"Missing required environment variable: {name}")
    return v


def _utc_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def _download_blob_text(credential: DefaultAzureCredential, account_url: str, container: str, blob_name: str) -> str:
    bsc = BlobServiceClient(account_url=account_url, credential=credential)
    bc = bsc.get_blob_client(container=container, blob=blob_name)
    data = bc.download_blob().readall()
    try:
        return data.decode("utf-8")
    except Exception:
        return data.decode("utf-8", errors="replace")


def _ensure_cosmos_container(credential: DefaultAzureCredential, endpoint: str, database_name: str, container_name: str, partition_key_path: str):
    client = CosmosClient(url=endpoint, credential=credential)
    db = client.create_database_if_not_exists(id=database_name)
    container = db.create_container_if_not_exists(
        id=container_name,
        partition_key=PartitionKey(path=partition_key_path),
        offer_throughput=int(os.getenv("COSMOS_THROUGHPUT", "400")),
    )
    return container


def _upsert_result(container, item: dict):
    container.upsert_item(item)


def _send_eventgrid_notification(credential: DefaultAzureCredential, topic_endpoint: str, subject: str, event_type: str, data: dict):
    client = EventGridPublisherClient(topic_endpoint, credential)
    event = {
        "id": str(uuid.uuid4()),
        "subject": subject,
        "eventType": event_type,
        "eventTime": _utc_now_iso(),
        "dataVersion": "1.0",
        "data": data,
    }
    client.send([event])


def _process_content(content: str) -> dict:
    lines = content.splitlines()
    size = len(content.encode("utf-8", errors="replace"))
    return {
        "lineCount": len(lines),
        "byteCount": size,
        "preview": content[:2000],
    }


